sql:
SELECT COUNT(DISTINCT b.borrower_id)
FROM borrowers AS b
INNER JOIN payment_schedules AS ps ON b.loan_id = ps.loan_id;

SELECT loan_type, description 
FROM loan_types
WHERE loan_type_id = 0;

SELECT officer_id, COUNT(loan_id) AS portfolio_size
FROM loan_decisions
GROUP BY officer_id;

SELECT credit_score 
FROM borrowers 
WHERE borrower_id = 1;

SELECT AVG(loan_amnt) 
FROM loans 
WHERE loan_status = 'Current' AND loan_type = 'mortgage';

SELECT payment_method, SUM(payment_amount) AS total_payment_amount
FROM payment_schedules
GROUP BY payment_method;

external_knowledge:
- 'the last six months' refers to the time period from six months ago to the current date;
- 'are not high risk' means the risk level is either 'Low' or 'Medium';
- 'are not in default' means the loan has been paid according to the schedule;
- 'no missed payments' indicates that the borrower has made all payments on time.

sql:
SELECT *
FROM borrowers
CROSS JOIN loans;

SELECT name
FROM borrowers
WHERE credit_score = (SELECT MAX(credit_score) FROM borrowers);

SELECT name, email, phone 
FROM borrowers 
WHERE loan_id IN (SELECT loan_id FROM loans WHERE bad_loan = 1);

SELECT loan_id, term, grade, purpose, int_rate, installment, loan_status, loan_amnt, emp_length, annual_inc, dti, delinq_2yrs, revol_bal, revol_util, total_acc, num_tl_90g_dpd_24m, loan_type 
FROM loans 
WHERE emp_length > (
    SELECT AVG(emp_length) 
    FROM loans
);
